  private async scheduleSinglePM(
    pm: PendingPM,
    trackAvailability: TrackAvailability[],
    laborCapacity: LaborCapacity[],
    materialPositions: MaterialPosition[],
    alreadyScheduled: ScheduledPM[]
  ): Promise<ScheduleAttemptResult> {
    const pmType = pm.pmType;

    // Find valid dates within compliance window
    const validDates = this.getValidDates(
      pm.constraintStart,
      pm.constraintEnd,
      pmType.minTrackDays
    );

    for (const targetDate of validDates) {
      // Check track availability
      const track = this.findAvailableTrack(
        targetDate,
        pmType.trackType,
        pmType.minTrackDays,
        trackAvailability
      );

      if (!track) continue;

      // Check labor capacity
      const laborOk = this.checkLaborCapacity(
        targetDate,
        pmType.estimatedHours,
        laborCapacity
      );

      if (!laborOk) continue;

      // Check material availability
      const materialCheck = await this.checkMaterialAvailability(
        pm,
        targetDate,
        materialPositions
      );

      if (materialCheck.blocked) {
        // Within hard constraint window - cannot schedule
        if (this.isWithinHardWindow(targetDate)) {
          return {
            scheduled: null,
            reason: `Material unavailable: ${materialCheck.missingParts.join(', ')}`,
            suggestedDate: materialCheck.suggestedDate,
            materialWarning: {
              pmId: pm.id,
              trainId: pm.trainId,
              missingParts: materialCheck.missingParts,
              expectedAvailability: materialCheck.expectedDelivery
            }
          };
        }
        // Soft constraint window - add warning but continue
        continue;
      }

      // Schedule found!
      return {
        scheduled: {
          pmId: pm.id,
          trainId: pm.trainId,
          pmTypeId: pmType.id,
          targetDate,
          trackId: track.id,
          assignedHours: pmType.estimatedHours,
          constraintStart: pm.constraintStart,
          constraintEnd: pm.constraintEnd
        },
        reason: null,
        materialWarning: materialCheck.warning
      };
    }

    // No valid slot found
    return {
      scheduled: null,
      reason: 'No available slot within compliance window',
      suggestedDate: addDays(pm.constraintEnd, 7)
    };
  }

  private async checkMaterialAvailability(
    pm: PendingPM,
    targetDate: Date,
    materialPositions: MaterialPosition[]
  ): Promise<MaterialCheckResult> {
    const requirements = await this.getPMRequirements(pm.pmType.id);
    const missingParts: string[] = [];
    let earliestDelivery: Date | null = null;

    for (const req of requirements) {
      if (req.criticality === 'CONSUMABLE') continue;

      const position = materialPositions.find(
        p => p.partNumber === req.partNumber && p.depotId === pm.depotId
      );

      const available = position?.quantityAvailable || 0;

      if (available < req.quantityPerPM) {
        if (req.criticality === 'BLOCKING') {
          missingParts.push(req.partNumber);

          if (position?.nextDeliveryDate) {
            const delivery = new Date(position.nextDeliveryDate);
            if (!earliestDelivery || delivery < earliestDelivery) {
              earliestDelivery = delivery;
            }
          }
        }
      }
    }

    return {
      blocked: missingParts.length > 0 && 
               this.isWithinHardWindow(targetDate),
      missingParts,
      expectedDelivery: earliestDelivery,
      suggestedDate: earliestDelivery 
        ? addDays(earliestDelivery, 1)
        : null,
      warning: missingParts.length > 0 ? {
        type: 'LOW_STOCK',
        parts: missingParts,
        message: `Parts may be unavailable: ${missingParts.join(', ')}`
      } : null
    };
  }
}
