  3489→        where: isNull(pmSchedule.scenarioId)
  3490→      });
  3491→    }
  3492→    
  3493→    // Get all deltas in order
  3494→    const deltas = await this.db.query.scenarioDeltas.findMany({
  3495→      where: eq(scenarioDeltas.scenarioId, scenarioId),
  3496→      orderBy: asc(scenarioDeltas.sequenceNum)
  3497→    });
