          })
          .onConflictDoUpdate({
            target: pmSchedule.id,
            set: {
              targetDate: pm.targetDate,
              assignedTrackId: pm.assignedTrackId,
              assignedHours: pm.assignedHours,
              updatedAt: new Date()
            }
          });
      }
    });

    // Mark scenario as promoted
    await this.db.update(scenarios)
      .set({
        status: 'PROMOTED',
        promotedToBaselineId: baseline.id,
        promotedAt: new Date(),
        promotedBy: userId
      })
      .where(eq(scenarios.id, scenarioId));

    return baseline;
  }
}
